import React, { useEffect, useState } from 'react';
import { LogOut, Users, GraduationCap, Search, Database, RefreshCw, LayoutDashboard, Briefcase, TrendingUp, PieChart as PieChartIcon, BarChart3, AlertCircle, UserCheck, Target, Building2, User } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { Student } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell, Sector 
} from 'recharts';

interface AdminDashboardProps {
  onLogout: () => void;
}

interface AnalyticsState {
  totalRespondents: number;
  employedCount: number;
  unemployedCount: number;
  selfEmployedCount: number;
  retiredCount: number;
  industryData: { name: string; value: number }[];
  unemploymentReasonData: { name: string; value: number }[];
  alignmentReasonData: { name: string; value: number }[];
  retirementReasonData: { name: string; value: number }[];
  alignmentRate: { name: string; value: number }[];
}

const COLORS = ['#006400', '#FFD700', '#EF4444', '#6B7280', '#3B82F6'];
const ALIGNMENT_COLORS = ['#006400', '#fbbf24']; // Green for Related, Amber for Non-Related

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [currentTab, setCurrentTab] = useState<'dashboard' | 'users'>('dashboard');

  // User Management State
  const [userFilter, setUserFilter] = useState<'graduating' | 'alumni'>('graduating');
  const [students, setStudents] = useState<Student[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Analytics State
  const [loadingAnalytics, setLoadingAnalytics] = useState(true);
  const [analytics, setAnalytics] = useState<AnalyticsState>({
    totalRespondents: 0,
    employedCount: 0,
    unemployedCount: 0,
    selfEmployedCount: 0,
    retiredCount: 0,
    industryData: [],
    unemploymentReasonData: [],
    alignmentReasonData: [],
    retirementReasonData: [],
    alignmentRate: []
  });

  // --- Data Fetching: Users ---
  const fetchUsers = async () => {
    setLoadingUsers(true);
    const table = userFilter === 'graduating' ? 'students' : 'alumni';

    const { data, error } = await supabase
      .from(table)
      .select('*')
      .order('last_name', { ascending: true });

    if (!error && data) {
      setStudents(data as Student[]);
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    if (currentTab === 'users') {
        fetchUsers();
    }
  }, [currentTab, userFilter]);

  // --- Data Fetching: Analytics ---
  const fetchAnalytics = async () => {
      setLoadingAnalytics(true);
      try {
        // Fetch all employment info
        const { data, error } = await supabase
            .from('employment_information')
            .select('*');

        if (error) throw error;
        if (!data) return;

        const records = data;
        const total = records.length;

        // 1. Status Counts
        const employed = records.filter(r => r.employment_status === 'Employed').length;
        const selfEmployed = records.filter(r => r.employment_status === 'Self-employed').length;
        const unemployed = records.filter(r => r.employment_status === 'Unemployed').length;
        const retired = records.filter(r => r.employment_status === 'Retired').length;

        // 2. Industry Distribution
        const industryMap: Record<string, number> = {};
        records.filter(r => r.industry).forEach(r => {
            const ind = r.industry as string;
            industryMap[ind] = (industryMap[ind] || 0) + 1;
        });
        const industryData = Object.entries(industryMap)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, 5); // Top 5

        // 3. Unemployment Reasons
        const unempReasonMap: Record<string, number> = {};
        records.filter(r => r.unemployed_reasons).forEach(r => {
             // Basic text normalization/grouping could happen here
             const reason = r.unemployed_reasons as string;
             // Truncate long reasons for charts
             const shortReason = reason.length > 30 ? reason.substring(0, 30) + '...' : reason;
             unempReasonMap[shortReason] = (unempReasonMap[shortReason] || 0) + 1;
        });
        const unemploymentReasonData = Object.entries(unempReasonMap)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, 5);

        // 4. Misalignment Reasons
        const misalignMap: Record<string, number> = {};
        records.filter(r => r.alignment_reason).forEach(r => {
            const reason = r.alignment_reason as string;
            misalignMap[reason] = (misalignMap[reason] || 0) + 1;
        });
        const alignmentReasonData = Object.entries(misalignMap)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value);

        // 5. Retirement Reasons
        const retireMap: Record<string, number> = {};
        records.filter(r => r.retirement_reason).forEach(r => {
            const reason = r.retirement_reason as string;
            retireMap[reason] = (retireMap[reason] || 0) + 1;
        });
        const retirementReasonData = Object.entries(retireMap)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value);

        // 6. Overall Alignment Rate
        const related = records.filter(r => r.job_alignment === 'Related').length;
        const nonRelated = records.filter(r => r.job_alignment === 'Non-Related').length;
        const alignmentRate = [
            { name: 'Related', value: related },
            { name: 'Non-Related', value: nonRelated }
        ];

        setAnalytics({
            totalRespondents: total,
            employedCount: employed,
            unemployedCount: unemployed,
            selfEmployedCount: selfEmployed,
            retiredCount: retired,
            industryData,
            unemploymentReasonData,
            alignmentReasonData,
            retirementReasonData,
            alignmentRate
        });

      } catch (err) {
          console.error("Analytics fetch error:", err);
      } finally {
          setLoadingAnalytics(false);
      }
  };

  useEffect(() => {
    if (currentTab === 'dashboard') {
        fetchAnalytics();
    }
  }, [currentTab]);

  // --- Filtering Users ---
  const filteredStudents = students.filter(student => 
    student.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.student_number.includes(searchTerm)
  );

  // --- Percentage Helper ---
  const getPercent = (count: number) => {
      if (analytics.totalRespondents === 0) return 0;
      return Math.round((count / analytics.totalRespondents) * 100);
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-800">

      {/* Sidebar / Navigation (Top for Mobile, Left for Desktop potentially, but sticking to top for now similar to user dashboard) */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30 shadow-sm">
        <div className="container mx-auto px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center space-x-3">
             <div className="w-10 h-10 bg-gray-900 rounded-xl flex items-center justify-center shadow-lg">
                 <Database className="text-luGold w-5 h-5" />
             </div>
             <div>
                <h1 className="text-xl font-bold font-display text-gray-900">Admin Portal</h1>
                <p className="text-[10px] text-gray-500 uppercase tracking-widest font-semibold">Laguna University</p>
             </div>
          </div>

          <div className="flex bg-gray-100 p-1 rounded-xl">
             <button 
                onClick={() => setCurrentTab('dashboard')}
                className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${currentTab === 'dashboard' ? 'bg-white text-luGreen shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
             >
                <LayoutDashboard size={16} /> Dashboard
             </button>
             <button 
                onClick={() => setCurrentTab('users')}
                className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${currentTab === 'users' ? 'bg-white text-luGreen shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
             >
                <Users size={16} /> User Management
             </button>
          </div>

          <button 
            onClick={onLogout}
            className="flex items-center space-x-2 text-sm font-bold text-red-500 hover:bg-red-50 px-4 py-2 rounded-lg transition-colors"
          >
            <LogOut size={16} />
            <span className="hidden md:inline">Sign Out</span>
          </button>
        </div>
      </header>

      <main className="container mx-auto px-6 py-8">

        {/* === ANALYTICS DASHBOARD === */}
        {currentTab === 'dashboard' && (
            <div className="space-y-8 animate-fade-in">

                {/* 1. KEY CARDS (Percentages) */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                    {/* Employed Card */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 rounded-xl bg-green-50 text-luGreen group-hover:bg-luGreen group-hover:text-white transition-colors">
                                <Briefcase size={24} />
                            </div>
                            <span className="bg-green-100 text-green-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.employedCount} users</span>
                        </div>
                        <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.employedCount)}%</h3>
                        <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Employed</p>
                        <div className="absolute bottom-0 left-0 h-1 bg-luGreen w-full opacity-50"></div>
                    </div>

                    {/* Unemployed Card */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 rounded-xl bg-red-50 text-red-500 group-hover:bg-red-500 group-hover:text-white transition-colors">
                                <AlertCircle size={24} />
                            </div>
                            <span className="bg-red-100 text-red-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.unemployedCount} users</span>
                        </div>
                        <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.unemployedCount)}%</h3>
                        <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Unemployed</p>
                        <div className="absolute bottom-0 left-0 h-1 bg-red-500 w-full opacity-50"></div>
                    </div>

                    {/* Self-Employed Card */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 rounded-xl bg-amber-50 text-amber-500 group-hover:bg-amber-500 group-hover:text-white transition-colors">
                                <Building2 size={24} />
                            </div>
                            <span className="bg-amber-100 text-amber-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.selfEmployedCount} users</span>
                        </div>
                        <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.selfEmployedCount)}%</h3>
                        <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Self-Employed</p>
                        <div className="absolute bottom-0 left-0 h-1 bg-amber-500 w-full opacity-50"></div>
                    </div>

                    {/* Retired Card */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 rounded-xl bg-gray-100 text-gray-500 group-hover:bg-gray-600 group-hover:text-white transition-colors">
                                <UserCheck size={24} />
                            </div>
                            <span className="bg-gray-200 text-gray-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.retiredCount} users</span>
                        </div>
                        <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.retiredCount)}%</h3>
                        <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Retired</p>
                        <div className="absolute bottom-0 left-0 h-1 bg-gray-500 w-full opacity-50"></div>
                    </div>
                </div>

                {/* 2. MAIN ANALYTICS SECTION */}
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                    {/* Industry Distribution */}
                    <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-blue-50 text-blue-600 rounded-lg"><BarChart3 size={20}/></div>
                            <h4 className="font-bold text-gray-800">Top 5 Employment Industries</h4>
                        </div>
                        <div className="h-64 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart layout="vertical" data={analytics.industryData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3} />
                                    <XAxis type="number" hide />
                                    <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                                    <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} cursor={{fill: '#eff6ff'}} />
                                    <Bar dataKey="value" fill="#3B82F6" radius={[0, 4, 4, 0]} barSize={20} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                     {/* Overall Alignment Rate */}
                    <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex flex-col">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-green-50 text-luGreen rounded-lg"><Target size={20}/></div>
                            <h4 className="font-bold text-gray-800">Program Alignment Rate</h4>
                        </div>
                        <div className="flex-grow flex items-center justify-center relative">
                             <ResponsiveContainer width="100%" height={250}>
                                <PieChart>
                                    <Pie
                                        data={analytics.alignmentRate}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={60}
                                        outerRadius={80}
                                        fill="#8884d8"
                                        paddingAngle={5}
                                        dataKey="value"
                                    >
                                        {analytics.alignmentRate.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={ALIGNMENT_COLORS[index % ALIGNMENT_COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <Tooltip contentStyle={{ borderRadius: '12px' }} />
                                    <Legend verticalAlign="bottom" height={36}/>
                                </PieChart>
                            </ResponsiveContainer>
                            {/* Center Text */}
                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none pb-8">
                                <div className="text-center">
                                    <span className="text-3xl font-black text-gray-800">
                                        {analytics.alignmentRate.length > 0 
                                            ? Math.round((analytics.alignmentRate[0].value / (analytics.alignmentRate[0].value + analytics.alignmentRate[1].value || 1)) * 100)
                                            : 0}%
                                    </span>
                                    <p className="text-xs text-gray-400 font-bold uppercase">Aligned</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Top Unemployment Reasons */}
                    <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-red-50 text-red-600 rounded-lg"><AlertCircle size={20}/></div>
                            <h4 className="font-bold text-gray-800">Top Unemployment Reasons</h4>
                        </div>
                        <div className="h-64 w-full">
                             <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={analytics.unemploymentReasonData}>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.3} />
                                    <XAxis dataKey="name" tick={{fontSize: 10}} interval={0} angle={-15} textAnchor="end" height={60}/>
                                    <YAxis />
                                    <Tooltip contentStyle={{ borderRadius: '12px' }} cursor={{fill: '#fef2f2'}} />
                                    <Bar dataKey="value" fill="#EF4444" radius={[4, 4, 0, 0]} barSize={40} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Misalignment Reasons */}
                    <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-amber-50 text-amber-600 rounded-lg"><PieChartIcon size={20}/></div>
                            <h4 className="font-bold text-gray-800">Reasons for Job Misalignment</h4>
                        </div>
                        <div className="h-64 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart layout="vertical" data={analytics.alignmentReasonData} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3} />
                                    <XAxis type="number" hide />
                                    <YAxis dataKey="name" type="category" width={120} tick={{fontSize: 11}} />
                                    <Tooltip contentStyle={{ borderRadius: '12px' }} cursor={{fill: '#fffbeb'}} />
                                    <Bar dataKey="value" fill="#F59E0B" radius={[0, 4, 4, 0]} barSize={20} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Retirement Reasons (Full Width if needed, or half) */}
                    <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm lg:col-span-2">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-gray-100 text-gray-600 rounded-lg"><UserCheck size={20}/></div>
                            <h4 className="font-bold text-gray-800">Retirement Reasons Overview</h4>
                        </div>
                         <div className="h-64 w-full">
                             <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={analytics.retirementReasonData}>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.3} />
                                    <XAxis dataKey="name" />
                                    <YAxis />
                                    <Tooltip contentStyle={{ borderRadius: '12px' }} cursor={{fill: '#f3f4f6'}} />
                                    <Bar dataKey="value" fill="#6B7280" radius={[4, 4, 0, 0]} barSize={50} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                </div>
            </div>
        )}

        {/* === USER MANAGEMENT SECTION === */}
        {currentTab === 'users' && (
            <div className="space-y-6 animate-fade-in">
                 {/* Stats & Tabs */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div 
                        onClick={() => setUserFilter('graduating')}
                        className={`p-6 rounded-2xl border-2 cursor-pointer transition-all duration-300 relative overflow-hidden group ${userFilter === 'graduating' ? 'bg-white border-luGreen shadow-lg' : 'bg-gray-100 border-transparent hover:bg-white hover:border-gray-200'}`}
                    >
                        <div className="flex justify-between items-start">
                            <div className={`p-3 rounded-xl ${userFilter === 'graduating' ? 'bg-green-100 text-luGreen' : 'bg-gray-200 text-gray-500'}`}>
                                <GraduationCap size={24} />
                            </div>
                        </div>
                        <h3 className="mt-4 text-xl font-bold text-gray-900">Graduating Students</h3>
                        <p className="text-xs text-gray-500">View 4th Year Records</p>
                    </div>

                    <div 
                        onClick={() => setUserFilter('alumni')}
                        className={`p-6 rounded-2xl border-2 cursor-pointer transition-all duration-300 relative overflow-hidden group ${userFilter === 'alumni' ? 'bg-white border-luGold shadow-lg' : 'bg-gray-100 border-transparent hover:bg-white hover:border-gray-200'}`}
                    >
                        <div className="flex justify-between items-start">
                            <div className={`p-3 rounded-xl ${userFilter === 'alumni' ? 'bg-amber-100 text-amber-600' : 'bg-gray-200 text-gray-500'}`}>
                                <Users size={24} />
                            </div>
                        </div>
                        <h3 className="mt-4 text-xl font-bold text-gray-900">Alumni Records</h3>
                        <p className="text-xs text-gray-500">View Graduates</p>
                    </div>
                </div>

                {/* Table Section */}
                <div className="bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden">

                    {/* Toolbar */}
                    <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4">
                        <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                            {userFilter === 'graduating' ? 'Graduating Students List' : 'Alumni Records'}
                            <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs">{filteredStudents.length}</span>
                        </h2>
                        <div className="flex items-center gap-3 w-full sm:w-auto">
                            <div className="relative flex-1 sm:flex-initial">
                                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                                <input 
                                    type="text" 
                                    placeholder="Search name or ID..." 
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                    className="pl-9 pr-4 py-2 rounded-xl bg-gray-50 border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen w-full sm:w-64"
                                />
                            </div>
                            <button 
                                onClick={fetchUsers}
                                className="p-2 bg-gray-50 hover:bg-gray-100 text-gray-600 rounded-xl border border-gray-200 transition-colors"
                                title="Refresh Data"
                            >
                                <RefreshCw className={`w-4 h-4 ${loadingUsers ? 'animate-spin' : ''}`} />
                            </button>
                        </div>
                    </div>

                    {/* Table */}
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-gray-50/50 border-b border-gray-100 text-xs uppercase tracking-wider text-gray-500 font-semibold">
                                    <th className="px-6 py-4">Student Info</th>
                                    <th className="px-6 py-4">Program</th>
                                    <th className="px-6 py-4">Contact</th>
                                    <th className="px-6 py-4">Batch/Year</th>
                                    <th className="px-6 py-4 text-right">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {loadingUsers ? (
                                    <tr>
                                        <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                                            <div className="flex flex-col items-center">
                                                <RefreshCw className="w-6 h-6 animate-spin mb-2" />
                                                Loading records...
                                            </div>
                                        </td>
                                    </tr>
                                ) : filteredStudents.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                                            No records found matching your search.
                                        </td>
                                    </tr>
                                ) : (
                                    filteredStudents.map((student, index) => (
                                        <tr key={index} className="hover:bg-gray-50/80 transition-colors group">
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col">
                                                    <span className="font-bold text-gray-900">{student.last_name}, {student.first_name}</span>
                                                    <span className="text-xs text-luGreen font-mono mt-0.5">{student.student_number}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className="text-sm font-medium text-gray-700">{student.program}</span>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col text-sm text-gray-600">
                                                    <span>{student.email || 'N/A'}</span>
                                                    <span className="text-xs text-gray-400">{student.contact_no}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-50 text-blue-800">
                                                    {student.year_level}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold uppercase tracking-wide ${
                                                    userFilter === 'graduating' ? 'bg-green-100 text-luGreen-dark' : 'bg-amber-100 text-amber-800'
                                                }`}>
                                                    {userFilter === 'graduating' ? 'Enrolled' : 'Graduate'}
                                                </span>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
};

