import React, { useState, useEffect } from 'react';
import { GraduationCap, Users, Search, RefreshCw } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { Student } from '../types';

const UserManagement: React.FC = () => {
  const [userFilter, setUserFilter] = useState<'graduating' | 'alumni'>('graduating');
  const [students, setStudents] = useState<Student[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchUsers = async () => {
    setLoadingUsers(true);
    const table = userFilter === 'graduating' ? 'students' : 'alumni';

    const { data, error } = await supabase
      .from(table)
      .select('*')
      .order('last_name', { ascending: true });

    if (!error && data) {
      setStudents(data as Student[]);
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [userFilter]);

  const filteredStudents = students.filter(student => 
    student.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.student_number.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-fade-in">
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                <h2 className="text-2xl font-bold text-gray-800 font-display">User Management</h2>
                <p className="text-gray-500">View and manage student and alumni records.</p>
                </div>
                {/* Stats Tabs */}
                <div className="bg-white p-1 rounded-xl border border-gray-200 shadow-sm flex">
                <button 
                    onClick={() => setUserFilter('graduating')}
                    className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${userFilter === 'graduating' ? 'bg-green-50 text-luGreen shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    <GraduationCap size={16} /> Graduating
                </button>
                <button 
                    onClick={() => setUserFilter('alumni')}
                    className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${userFilter === 'alumni' ? 'bg-amber-50 text-amber-600 shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    <Users size={16} /> Alumni
                </button>
                </div>
        </div>

        {/* Table Section */}
        <div className="bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden">
            {/* Toolbar */}
            <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4">
                <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                    {userFilter === 'graduating' ? 'Graduating Students List' : 'Alumni Records'}
                    <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs">{filteredStudents.length}</span>
                </h2>
                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:flex-initial">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                        <input 
                            type="text" 
                            placeholder="Search name or ID..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-9 pr-4 py-2 rounded-xl bg-gray-50 border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen w-full sm:w-64"
                        />
                    </div>
                    <button 
                        onClick={fetchUsers}
                        className="p-2 bg-gray-50 hover:bg-gray-100 text-gray-600 rounded-xl border border-gray-200 transition-colors"
                        title="Refresh Data"
                    >
                        <RefreshCw className={`w-4 h-4 ${loadingUsers ? 'animate-spin' : ''}`} />
                    </button>
                </div>
            </div>

            {/* Table */}
            <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50/50 border-b border-gray-100 text-xs uppercase tracking-wider text-gray-500 font-semibold">
                            <th className="px-6 py-4">Student Info</th>
                            <th className="px-6 py-4">Program</th>
                            <th className="px-6 py-4">Contact</th>
                            <th className="px-6 py-4">Batch/Year</th>
                            <th className="px-6 py-4 text-right">Status</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                        {loadingUsers ? (
                            <tr>
                                <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                                    <div className="flex flex-col items-center">
                                        <RefreshCw className="w-6 h-6 animate-spin mb-2" />
                                        Loading records...
                                    </div>
                                </td>
                            </tr>
                        ) : filteredStudents.length === 0 ? (
                            <tr>
                                <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                                    No records found matching your search.
                                </td>
                            </tr>
                        ) : (
                            filteredStudents.map((student, index) => (
                                <tr key={index} className="hover:bg-gray-50/80 transition-colors group">
                                    <td className="px-6 py-4">
                                        <div className="flex flex-col">
                                            <span className="font-bold text-gray-900">{student.last_name}, {student.first_name}</span>
