    "Diploma in Midwifery"
];

const ALIGNMENT_COLORS = ['#006400', '#fbbf24']; // Green for Related, Amber for Non-Related

// --- Types ---
interface AnalyticsState {
  totalRespondents: number;
  employedCount: number;
  unemployedCount: number;
  selfEmployedCount: number;
  retiredCount: number;
  industryData: { name: string; value: number }[];
  unemploymentReasonData: { name: string; value: number }[];
  alignmentReasonData: { name: string; value: number }[];
  retirementReasonData: { name: string; value: number }[];
  alignmentRate: { name: string; value: number }[];
}

// Master record type that combines employment info with user profile info
interface MasterRecord {
    employment_status: string;
    industry?: string;
    unemployed_reasons?: string;
    alignment_reason?: string;
    retirement_reason?: string;
    job_alignment?: string;
    // Profile Data
    program: string;
    year_level: string; // Batch
}

const HomePage: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [masterData, setMasterData] = useState<MasterRecord[]>([]);

  // Filters
  const [selectedYear, setSelectedYear] = useState<string>('All');
  const [selectedCourse, setSelectedCourse] = useState<string>('All');
  const [availableYears, setAvailableYears] = useState<string[]>([]);

  // Analytics State (Derived)
  const [analytics, setAnalytics] = useState<AnalyticsState>({
    totalRespondents: 0,
    employedCount: 0,
    unemployedCount: 0,
    selfEmployedCount: 0,
    retiredCount: 0,
    industryData: [],
    unemploymentReasonData: [],
    alignmentReasonData: [],
    retirementReasonData: [],
    alignmentRate: []
  });

  // --- 1. Data Fetching (Joins Employment with User Profile) ---
  const fetchData = async () => {
      setLoading(true);
      try {
        // A. Fetch all employment records
        const { data: empData, error: empError } = await supabase
            .from('employment_information')
            .select('*');

        if (empError) throw empError;
        if (!empData) return;

        // B. Fetch all survey responses to map Employment -> User ID
        const surveyIds = empData.map(e => e.survey_response_id);
        const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id, student_id, alumni_id, respondent_type')
            .in('id', surveyIds);

        if (surveyError) throw surveyError;

        // C. Fetch User Profiles (Students & Alumni) to get Program/Year
        // We need to fetch all to map them efficiently locally
        const [ { data: students }, { data: alumni } ] = await Promise.all([
            supabase.from('students').select('id, program, year_level'),
            supabase.from('alumni').select('id, program, year_level')
        ]);

        // D. Build Maps for fast lookup
        const studentMap = new Map(students?.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni?.map((a: any) => [a.id, a]));
        const surveyMap = new Map(surveyData?.map((s: any) => [s.id, s]));

        // E. Construct Master Records
        const combined: MasterRecord[] = [];

        empData.forEach(record => {
            const survey = surveyMap.get(record.survey_response_id) as any;
            if (!survey) return;

            let userProfile: any = null;
            if (survey.respondent_type === 'student') {
                userProfile = studentMap.get(survey.student_id);
            } else {
                userProfile = alumniMap.get(survey.alumni_id);
            }

            if (userProfile) {
                // Normalize Year Level if needed
                const year = userProfile.year_level || 'Unknown';

                combined.push({
                    employment_status: record.employment_status,
                    industry: record.industry,
                    unemployed_reasons: record.unemployed_reasons,
                    alignment_reason: record.alignment_reason,
                    retirement_reason: record.retirement_reason,
                    job_alignment: record.job_alignment,
                    program: userProfile.program || 'Unknown',
                    year_level: year
                });
            }
        });

        // Set Available Years for Filter (Static 2026-2006)
        const staticYears = [];
        for (let y = 2026; y >= 2006; y--) {
            staticYears.push(y.toString());
        }
        setAvailableYears(staticYears);

        setMasterData(combined);

      } catch (err) {
          console.error("Data fetch error:", err);
      } finally {
          setLoading(false);
      }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- 2. Filter Logic & Calculation ---
  useEffect(() => {
    // A. Apply Filters
    const filtered = masterData.filter(record => {
        const matchesYear = selectedYear === 'All' || record.year_level === selectedYear;
        // Basic inclusion check for program to handle slight variations, or exact match if preferred
        const matchesCourse = selectedCourse === 'All' || record.program === selectedCourse;
        return matchesYear && matchesCourse;
    });

    // B. Calculate Analytics based on Filtered Data
    const total = filtered.length;
    const employed = filtered.filter(r => r.employment_status === 'Employed').length;
    const selfEmployed = filtered.filter(r => r.employment_status === 'Self-employed').length;
    const unemployed = filtered.filter(r => r.employment_status === 'Unemployed').length;
    const retired = filtered.filter(r => r.employment_status === 'Retired').length;

    // Maps for charts
    const industryMap: Record<string, number> = {};
    const unempReasonMap: Record<string, number> = {};
    const misalignMap: Record<string, number> = {};
    const retireMap: Record<string, number> = {};
    let relatedCount = 0;
    let nonRelatedCount = 0;

    filtered.forEach(r => {
        // Industry
        if (r.industry) industryMap[r.industry] = (industryMap[r.industry] || 0) + 1;

        // Unemployed Reasons
        if (r.unemployed_reasons) unempReasonMap[r.unemployed_reasons] = (unempReasonMap[r.unemployed_reasons] || 0) + 1;

        // Misalignment
        if (r.alignment_reason) misalignMap[r.alignment_reason] = (misalignMap[r.alignment_reason] || 0) + 1;

        // Retirement
        if (r.retirement_reason) retireMap[r.retirement_reason] = (retireMap[r.retirement_reason] || 0) + 1;

        // Alignment Rate
        if (r.job_alignment === 'Related') relatedCount++;
        if (r.job_alignment === 'Non-Related') nonRelatedCount++;
    });

    // Format for Recharts
    const formatChartData = (map: Record<string, number>, topN = 5) => 
        Object.entries(map)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, topN);

    setAnalytics({
        totalRespondents: total,
        employedCount: employed,
        selfEmployedCount: selfEmployed,
        unemployedCount: unemployed,
        retiredCount: retired,
        industryData: formatChartData(industryMap),
        unemploymentReasonData: formatChartData(unempReasonMap),
        alignmentReasonData: formatChartData(misalignMap),
        retirementReasonData: formatChartData(retireMap),
        alignmentRate: [
            { name: 'Related', value: relatedCount },
            { name: 'Non-Related', value: nonRelatedCount }
        ]
    });

  }, [masterData, selectedYear, selectedCourse]);


  const getPercent = (count: number) => {
      if (analytics.totalRespondents === 0) return 0;
      return Math.round((count / analytics.totalRespondents) * 100);
  };

  // Reusable Component for Reason Lists
  const ReasonListCard = ({ 
    title, 
    icon: Icon, 
    data, 
    colorClass, 
    barColorClass 
  }: { 
    title: string, 
    icon: any, 
    data: { name: string, value: number }[],
    colorClass: string,
    barColorClass: string
  }) => {
    const maxValue = Math.max(...data.map(d => d.value), 1);

    return (
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm h-full flex flex-col">
            <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-lg ${colorClass}`}>
                    <Icon size={20}/>
                </div>
                <h4 className="font-bold text-gray-800">{title}</h4>
            </div>

            <div className="space-y-4 flex-grow overflow-y-auto max-h-[300px] pr-2 custom-scrollbar">
                {data.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400 py-8">
                        <AlertCircle size={24} className="mb-2 opacity-50" />
                        <p className="text-xs font-medium">No data available for this filter</p>
                    </div>
                ) : (
                    data.map((item, index) => (
                        <div key={index} className="group">
                            <div className="flex justify-between items-center mb-1">
                                <span className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-0.5 rounded-md min-w-[24px] text-center mr-3">#{index + 1}</span>
                                <span className="text-sm font-semibold text-gray-700 flex-grow truncate mr-4" title={item.name}>
                                    {item.name}
                                </span>
                                <span className="text-sm font-bold text-gray-900">{item.value}</span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-2 overflow-hidden">
                                <div 
                                    className={`h-full rounded-full ${barColorClass} transition-all duration-500 ease-out`} 
                                    style={{ width: `${(item.value / maxValue) * 100}%` }}
                                ></div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">

        {/* --- Header & Filter Section --- */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end gap-6 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <div>
                <h2 className="text-2xl font-bold text-gray-800 font-display">Analytics Overview</h2>
                <p className="text-gray-500 mt-1">Real-time data visualization of alumni employment status.</p>
            </div>

            {/* Filter Bar */}
            <div className="flex flex-col sm:flex-row gap-3 w-full xl:w-auto">
                {/* Year Filter */}
                <div className="relative group min-w-[140px]">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <TrendingUp size={16} className="text-gray-400 group-focus-within:text-luGreen"/>
                    </div>
                    <select 
                        value={selectedYear}
                        onChange={(e) => setSelectedYear(e.target.value)}
                        className="block w-full pl-10 pr-10 py-2.5 text-sm font-bold text-gray-700 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen outline-none appearance-none cursor-pointer hover:bg-white transition-all"
                    >
                        <option value="All">All Batches</option>
                        {availableYears.map(year => (
                            <option key={year} value={year}>{year}</option>
                        ))}
                    </select>
                    <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                        <ChevronDown size={14} className="text-gray-400"/>
                    </div>
                </div>

                {/* Course Filter */}
                <div className="relative group flex-grow xl:w-[400px]">
                     <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Filter size={16} className="text-gray-400 group-focus-within:text-luGreen"/>
                    </div>
                    <select 
                        value={selectedCourse}
                        onChange={(e) => setSelectedCourse(e.target.value)}
                        className="block w-full pl-10 pr-10 py-2.5 text-sm font-bold text-gray-700 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen outline-none appearance-none cursor-pointer hover:bg-white transition-all truncate"
                    >
                        <option value="All">All Programs / Courses</option>
                        {COURSES.map(course => (
                            <option key={course} value={course}>{course}</option>
                        ))}
                    </select>
                    <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                        <ChevronDown size={14} className="text-gray-400"/>
                    </div>
                </div>
            </div>
        </div>

        {/* KEY CARDS */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {/* Employed Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                <div className="flex justify-between items-start mb-4">
                    <div className="p-3 rounded-xl bg-green-50 text-luGreen group-hover:bg-luGreen group-hover:text-white transition-colors">
                        <Briefcase size={24} />
                    </div>
                    <span className="bg-green-100 text-green-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.employedCount}</span>
                </div>
