export const fetchLatestProfile = async (userId: string, userType: 'graduating' | 'alumni' | 'student'): Promise<FullProfileData | null> => {
    const idColumn = userType === 'graduating' ? 'student_id' : 'alumni_id';

    // 1. Get the most recent survey response ID
    const { data: latestSurvey, error: surveyError } = await supabase
        .from('survey_responses')
        .select('id')
        .eq(idColumn, userId)
        .order('submitted_at', { ascending: false })
        .limit(1)
        .single();

    if (surveyError || !latestSurvey) {
        return null; // No profile data saved yet
    }

    const surveyId = latestSurvey.id;

    // 2. Fetch related data in parallel
    const [education, employment, community, attributes] = await Promise.all([
        supabase.from('education_information').select('*').eq('survey_response_id', surveyId).single(),
        supabase.from('employment_history').select('*').eq('survey_response_id', surveyId),
        supabase.from('community_engagement').select('*').eq('survey_response_id', surveyId),
        supabase.from('alumni_attributes').select('*').eq('survey_response_id', surveyId).single()
    ]);

    return {
        education: education.data || {},
        employment: employment.data || [],
        community: community.data || [],
        attributes: attributes.data || {
            professionally_competent: 0,
            critical_thinker: 0,
            communicator: 0,
            lifelong_learner: 0,
            socially_responsible: 0,
            ethical_citizen: 0,
            innovative_worker: 0,
            people_oriented: 0,
            critical_thinking_skill: 0,
            creativity: 0,
            collaboration: 0,
            communication_skill: 0,
            information_literacy: 0,
            media_literacy: 0,
            technology_literacy: 0,
            flexibility: 0,
            leadership: 0,
            initiative: 0,
            productivity: 0,
            social_skills: 0
        }
    };
};

