import React, { useEffect, useState, useMemo } from 'react';
import { Briefcase, AlertCircle, UserCheck, Target, Building2, BarChart3, PieChart as PieChartIcon, TrendingUp, Users, Filter, ChevronDown, RefreshCw } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';

// --- Configuration ---
const COURSES = [
    "Bachelor of Elementary Education (BEED)",
    "Bachelor of Secondary Education (BSED) English",
    "Bachelor of Secondary Education (BSED) Science",
    "Bachelor of Secondary Education (BSED) Math",
    "Bachelor of Science in Entrepreneurship (BSE)",
    "Bachelor of Science in Tourism Management (BSTM)",
    "Bachelor of Science in Accountancy (BSA)",
    "Bachelor of Science in Accounting Information System (BSAIS)",
    "Bachelor of Science in Computer Science (BSCS)",
    "Bachelor of Science in Information Technology (BSIT)",
    "Bachelor of Science in Mechanical Engineering (BSME)",
    "Bachelor of Arts in Communication (BAC)",
    "Diploma in Midwifery"
];

const ALIGNMENT_COLORS = ['#006400', '#fbbf24']; // Green for Related, Amber for Non-Related

// --- Types ---
interface AnalyticsState {
  totalPopulationCount: number; // Total Students + Alumni in DB (Denominator)
  totalRespondents: number; // Total with Employment Records
  employedCount: number;
  unemployedCount: number;
  selfEmployedCount: number;
  retiredCount: number;
  industryData: { name: string; value: number }[];
  unemploymentReasonData: { name: string; value: number }[];
  alignmentReasonData: { name: string; value: number }[];
  retirementReasonData: { name: string; value: number }[];
  alignmentRate: { name: string; value: number }[];
}

// Master record type that combines employment info with user profile info
interface MasterRecord {
    employment_status: string;
    industry?: string;
    unemployed_reasons?: string;
    alignment_reason?: string;
    retirement_reason?: string;
    job_alignment?: string;
    // Profile Data
    program: string;
    year_level: string; // Batch
}

// Simplified User for Population Count
interface UserRecord {
    program: string;
    year_level: string;
}

const HomePage: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [masterData, setMasterData] = useState<MasterRecord[]>([]);
  const [allUsers, setAllUsers] = useState<UserRecord[]>([]);

  // Filters
  const [selectedYear, setSelectedYear] = useState<string>('All');
  const [selectedCourse, setSelectedCourse] = useState<string>('All');
  const [availableYears, setAvailableYears] = useState<string[]>([]);

  // Analytics State (Derived)
  const [analytics, setAnalytics] = useState<AnalyticsState>({
    totalPopulationCount: 0,
    totalRespondents: 0,
    employedCount: 0,
    unemployedCount: 0,
    selfEmployedCount: 0,
    retiredCount: 0,
    industryData: [],
    unemploymentReasonData: [],
    alignmentReasonData: [],
    retirementReasonData: [],
    alignmentRate: []
  });

  // --- 1. Data Fetching (Joins Employment with User Profile) ---
  const fetchData = async () => {
      setLoading(true);
      try {
        // A. Fetch all employment records
        const { data: empData, error: empError } = await supabase
            .from('employment_information')
            .select('*');

        if (empError) throw empError;

        // B. Fetch all survey responses to map Employment -> User ID
        const surveyIds = empData ? empData.map(e => e.survey_response_id) : [];
        const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id, student_id, alumni_id, respondent_type')
            .in('id', surveyIds);

        if (surveyError) throw surveyError;

        // C. Fetch User Profiles (Students & Alumni) to get Program/Year
        // We need to fetch all to map them efficiently locally AND to calculate Total Population
        const [ { data: students }, { data: alumni } ] = await Promise.all([
            supabase.from('students').select('id, program, year_level'),
            supabase.from('alumni').select('id, program, year_level')
        ]);

        // Store All Users for Population Denominator
        const population: UserRecord[] = [];
        if (students) {
            students.forEach((s: any) => population.push({ program: s.program, year_level: s.year_level || 'Unknown' }));
        }
        if (alumni) {
            alumni.forEach((a: any) => population.push({ program: a.program, year_level: a.year_level || 'Unknown' }));
        }
        setAllUsers(population);

        // D. Build Maps for fast lookup
        const studentMap = new Map(students?.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni?.map((a: any) => [a.id, a]));
        const surveyMap = new Map(surveyData?.map((s: any) => [s.id, s]));

        // E. Construct Master Records (Respondents)
        const combined: MasterRecord[] = [];

        if (empData) {
            empData.forEach(record => {
                const survey = surveyMap.get(record.survey_response_id) as any;
                if (!survey) return;

                let userProfile: any = null;
                if (survey.respondent_type === 'student') {
                    userProfile = studentMap.get(survey.student_id);
                } else {
                    userProfile = alumniMap.get(survey.alumni_id);
                }

                if (userProfile) {
                    // Normalize Year Level if needed
                    const year = userProfile.year_level || 'Unknown';

                    combined.push({
                        employment_status: record.employment_status,
                        industry: record.industry,
                        unemployed_reasons: record.unemployed_reasons,
                        alignment_reason: record.alignment_reason,
                        retirement_reason: record.retirement_reason,
                        job_alignment: record.job_alignment,
                        program: userProfile.program || 'Unknown',
                        year_level: year
                    });
                }
            });
        }

        // Set Available Years for Filter (Static 2026-2006)
        const staticYears = [];
        for (let y = 2026; y >= 2006; y--) {
            staticYears.push(y.toString());
        }
        setAvailableYears(staticYears);

        setMasterData(combined);

      } catch (err) {
          console.error("Data fetch error:", err);
      } finally {
          setLoading(false);
      }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- 2. Filter Logic & Calculation ---
  useEffect(() => {
    // A. Apply Filters to Respondents (MasterData)
    const filteredRespondents = masterData.filter(record => {
        const matchesYear = selectedYear === 'All' || record.year_level === selectedYear;
        const matchesCourse = selectedCourse === 'All' || record.program === selectedCourse;
        return matchesYear && matchesCourse;
    });

    // B. Apply Filters to Population (All Users) - This is our Denominator
    const filteredPopulation = allUsers.filter(user => {
        const matchesYear = selectedYear === 'All' || user.year_level === selectedYear;
        const matchesCourse = selectedCourse === 'All' || user.program === selectedCourse;
        return matchesYear && matchesCourse;
    });
    const totalPopulation = filteredPopulation.length;

    // C. Calculate Analytics based on Filtered Data
    const employed = filteredRespondents.filter(r => r.employment_status === 'Employed').length;
    const selfEmployed = filteredRespondents.filter(r => r.employment_status === 'Self-employed').length;
    const unemployed = filteredRespondents.filter(r => r.employment_status === 'Unemployed').length;
    const retired = filteredRespondents.filter(r => r.employment_status === 'Retired').length;

    // Maps for charts
    const industryMap: Record<string, number> = {};
    const unempReasonMap: Record<string, number> = {};
    const misalignMap: Record<string, number> = {};
    const retireMap: Record<string, number> = {};
    let relatedCount = 0;
    let nonRelatedCount = 0;

    filteredRespondents.forEach(r => {
        // Industry
        if (r.industry) industryMap[r.industry] = (industryMap[r.industry] || 0) + 1;

        // Unemployed Reasons
        if (r.unemployed_reasons) unempReasonMap[r.unemployed_reasons] = (unempReasonMap[r.unemployed_reasons] || 0) + 1;

        // Misalignment
        if (r.alignment_reason) misalignMap[r.alignment_reason] = (misalignMap[r.alignment_reason] || 0) + 1;

        // Retirement
        if (r.retirement_reason) retireMap[r.retirement_reason] = (retireMap[r.retirement_reason] || 0) + 1;

        // Alignment Rate
        if (r.job_alignment === 'Related') relatedCount++;
        if (r.job_alignment === 'Non-Related') nonRelatedCount++;
    });

    // Format for Recharts
    const formatChartData = (map: Record<string, number>, topN = 5) => 
        Object.entries(map)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, topN);

    setAnalytics({
        totalPopulationCount: totalPopulation,
        totalRespondents: filteredRespondents.length,
        employedCount: employed,
        selfEmployedCount: selfEmployed,
        unemployedCount: unemployed,
        retiredCount: retired,
        industryData: formatChartData(industryMap),
        unemploymentReasonData: formatChartData(unempReasonMap),
        alignmentReasonData: formatChartData(misalignMap),
        retirementReasonData: formatChartData(retireMap),
        alignmentRate: [
            { name: 'Related', value: relatedCount },
            { name: 'Non-Related', value: nonRelatedCount }
        ]
    });

  }, [masterData, allUsers, selectedYear, selectedCourse]);


  const getPercent = (count: number) => {
      // Calculate based on Total Population (Students + Alumni in database matching filter)
      if (analytics.totalPopulationCount === 0) return 0;
      return Math.round((count / analytics.totalPopulationCount) * 100);
  };

  // Reusable Component for Reason Lists
  const ReasonListCard = ({ 
    title, 
    icon: Icon, 
    data, 
    colorClass, 
    barColorClass 
  }: { 
    title: string, 
    icon: any, 
    data: { name: string, value: number }[],
    colorClass: string,
    barColorClass: string
  }) => {
    const maxValue = Math.max(...data.map(d => d.value), 1);

    return (
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm h-full flex flex-col">
            <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-lg ${colorClass}`}>
                    <Icon size={20}/>
                </div>
                <h4 className="font-bold text-gray-800">{title}</h4>
            </div>

            <div className="space-y-4 flex-grow overflow-y-auto max-h-[300px] pr-2 custom-scrollbar">
                {data.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400 py-8">
                        <AlertCircle size={24} className="mb-2 opacity-50" />
                        <p className="text-xs font-medium">No data available for this filter</p>
                    </div>
                ) : (
                    data.map((item, index) => (
                        <div key={index} className="group">
                            <div className="flex justify-between items-center mb-1">
                                <span className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-0.5 rounded-md min-w-[24px] text-center mr-3">#{index + 1}</span>
                                <span className="text-sm font-semibold text-gray-700 flex-grow truncate mr-4" title={item.name}>
                                    {item.name}
                                </span>
                                <span className="text-sm font-bold text-gray-900">{item.value}</span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-2 overflow-hidden">
                                <div 
                                    className={`h-full rounded-full ${barColorClass} transition-all duration-500 ease-out`} 
                                    style={{ width: `${(item.value / maxValue) * 100}%` }}
                                ></div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">

        {/* --- Header & Filter Section --- */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end gap-6 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <div>
                <h2 className="text-2xl font-bold text-gray-800 font-display">Analytics Overview</h2>
                <p className="text-gray-500 mt-1">Real-time data visualization of alumni employment status.</p>
            </div>

            {/* Filter Bar */}
            <div className="flex flex-col sm:flex-row gap-3 w-full xl:w-auto">
                {/* Year Filter */}
                <div className="relative group min-w-[140px]">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <TrendingUp size={16} className="text-gray-400 group-focus-within:text-luGreen"/>
                    </div>
                    <select 
                        value={selectedYear}
                        onChange={(e) => setSelectedYear(e.target.value)}
                        className="block w-full pl-10 pr-10 py-2.5 text-sm font-bold text-gray-700 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen outline-none appearance-none cursor-pointer hover:bg-white transition-all"
                    >
                        <option value="All">All Batches</option>
                        {availableYears.map(year => (
                            <option key={year} value={year}>{year}</option>
                        ))}
                    </select>
                    <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                        <ChevronDown size={14} className="text-gray-400"/>
                    </div>
                </div>

                {/* Course Filter */}
                <div className="relative group flex-grow xl:w-[400px]">
                     <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Filter size={16} className="text-gray-400 group-focus-within:text-luGreen"/>
                    </div>
                    <select 
                        value={selectedCourse}
                        onChange={(e) => setSelectedCourse(e.target.value)}
                        className="block w-full pl-10 pr-10 py-2.5 text-sm font-bold text-gray-700 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen outline-none appearance-none cursor-pointer hover:bg-white transition-all truncate"
                    >
                        <option value="All">All Programs / Courses</option>
                        {COURSES.map(course => (
                            <option key={course} value={course}>{course}</option>
                        ))}
                    </select>
                    <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                        <ChevronDown size={14} className="text-gray-400"/>
                    </div>
                </div>
            </div>
        </div>

        {/* KEY CARDS */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {/* Employed Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                <div className="flex justify-between items-start mb-4">
                    <div className="p-3 rounded-xl bg-green-50 text-luGreen group-hover:bg-luGreen group-hover:text-white transition-colors">
                        <Briefcase size={24} />
                    </div>
                    <span className="bg-green-100 text-green-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.employedCount} / {analytics.totalPopulationCount}</span>
                </div>
                <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.employedCount)}%</h3>
                <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Employed</p>
                <div className="absolute bottom-0 left-0 h-1 bg-luGreen w-full opacity-50"></div>
            </div>

            {/* Unemployed Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                <div className="flex justify-between items-start mb-4">
                    <div className="p-3 rounded-xl bg-red-50 text-red-500 group-hover:bg-red-500 group-hover:text-white transition-colors">
                        <AlertCircle size={24} />
                    </div>
                    <span className="bg-red-100 text-red-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.unemployedCount} / {analytics.totalPopulationCount}</span>
                </div>
                <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.unemployedCount)}%</h3>
                <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Unemployed</p>
                <div className="absolute bottom-0 left-0 h-1 bg-red-500 w-full opacity-50"></div>
            </div>

            {/* Self-Employed Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                <div className="flex justify-between items-start mb-4">
                    <div className="p-3 rounded-xl bg-amber-50 text-amber-500 group-hover:bg-amber-500 group-hover:text-white transition-colors">
                        <Building2 size={24} />
                    </div>
                    <span className="bg-amber-100 text-amber-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.selfEmployedCount} / {analytics.totalPopulationCount}</span>
                </div>
                <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.selfEmployedCount)}%</h3>
                <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Self-Employed</p>
                <div className="absolute bottom-0 left-0 h-1 bg-amber-500 w-full opacity-50"></div>
            </div>

            {/* Retired Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative overflow-hidden group hover:shadow-lg transition-all">
                <div className="flex justify-between items-start mb-4">
                    <div className="p-3 rounded-xl bg-gray-100 text-gray-500 group-hover:bg-gray-600 group-hover:text-white transition-colors">
                        <UserCheck size={24} />
                    </div>
                    <span className="bg-gray-200 text-gray-700 text-xs font-bold px-2 py-1 rounded-full">{analytics.retiredCount} / {analytics.totalPopulationCount}</span>
                </div>
                <h3 className="text-4xl font-black text-gray-800 mb-1">{getPercent(analytics.retiredCount)}%</h3>
                <p className="text-sm font-semibold text-gray-400 uppercase tracking-wide">Retired</p>
                <div className="absolute bottom-0 left-0 h-1 bg-gray-500 w-full opacity-50"></div>
            </div>
        </div>

        {/* VISUAL CHARTS SECTION (Industry & Alignment) */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

            {/* Industry Distribution - Keep as Graph */}
            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-blue-50 text-blue-600 rounded-lg"><BarChart3 size={20}/></div>
                    <h4 className="font-bold text-gray-800">Top 5 Employment Industries</h4>
                </div>
                <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart layout="vertical" data={analytics.industryData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3} />
                            <XAxis type="number" hide />
                            <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                            <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} cursor={{fill: '#eff6ff'}} />
                            <Bar dataKey="value" fill="#3B82F6" radius={[0, 4, 4, 0]} barSize={20} />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* Overall Alignment Rate - Keep as Pie Chart */}
            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-green-50 text-luGreen rounded-lg"><Target size={20}/></div>
                    <h4 className="font-bold text-gray-800">Program Alignment Rate</h4>
                </div>
                <div className="flex-grow flex items-center justify-center relative">
                    <ResponsiveContainer width="100%" height={250}>
                        <PieChart>
                            <Pie
                                data={analytics.alignmentRate}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                fill="#8884d8"
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {analytics.alignmentRate.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={ALIGNMENT_COLORS[index % ALIGNMENT_COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip contentStyle={{ borderRadius: '12px' }} />
                            <Legend verticalAlign="bottom" height={36}/>
                        </PieChart>
                    </ResponsiveContainer>
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none pb-8">
                        <div className="text-center">
                            <span className="text-3xl font-black text-gray-800">
                                {analytics.alignmentRate.length > 0 
                                    ? Math.round((analytics.alignmentRate[0].value / (analytics.alignmentRate[0].value + analytics.alignmentRate[1].value || 1)) * 100)
                                    : 0}%
                            </span>
                            <p className="text-xs text-gray-400 font-bold uppercase">Aligned</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* LIST CARDS SECTION (Reasons & Details) */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

            {/* Top Unemployment Reasons */}
            <ReasonListCard 
                title="Unemployment Reasons" 
                icon={AlertCircle}
                data={analytics.unemploymentReasonData}
                colorClass="bg-red-50 text-red-600"
                barColorClass="bg-red-500"
            />

            {/* Misalignment Reasons */}
            <ReasonListCard 
                title="Job Misalignment Reasons" 
                icon={PieChartIcon}
                data={analytics.alignmentReasonData}
                colorClass="bg-amber-50 text-amber-600"
                barColorClass="bg-amber-500"
            />

            {/* Retirement Reasons */}
            <ReasonListCard 
                title="Retirement Reasons" 
                icon={UserCheck}
                data={analytics.retirementReasonData}
                colorClass="bg-gray-100 text-gray-600"
                barColorClass="bg-gray-500"
            />

        </div>
    </div>
  );
};

export default HomePage;
